// Referenciando dados dos 4 nós anteriores
const dashData = $('Buscar Dashboard (KPIs do dia)').first().json;
const reportData = $('Buscar Relatório Mensal').first().json;
const boardData = $('Buscar Board do Funil').first().json;

// Conversas data (pode falhar se Conversas não estiver rodando)
let conversasData = null;
try {
  conversasData = $('Buscar Conversas do Dia').first().json;
} catch(e) {
  conversasData = null;
}

const dataHoje = new Date().toLocaleDateString('pt-BR');
const kpis = dashData.kpis || {};
const kpisMes = reportData.kpis || {};

// ─── Montar relatório ───
let msg = `📊 RELATÓRIO DO DIA — ${dataHoje}\n`;
msg += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

// KPIs do dia
msg += `📥 Novos leads hoje: ${kpis.total_leads || 0}\n`;
msg += `💰 Vendas fechadas: ${kpis.vendas_fechadas || 0}\n`;
msg += `📈 Taxa de conversão: ${kpis.taxa_conversao || '0%'}\n`;
msg += `⏳ Tarefas pendentes: ${kpis.tarefas_pendentes || 0}\n\n`;

// Métricas Conversas (NOVO)
if (conversasData && conversasData.conversations) {
  const convs = conversasData.conversations || [];
  const abertas = convs.filter(c => c.status === 'aberta').length;
  const encerradas = convs.filter(c => c.status === 'encerrada').length;
  const aguardando = convs.filter(c => c.status === 'aguardando').length;

  // Distribuição por responsável
  const respDist = {};
  convs.forEach(c => {
    const nome = c.responsavel_nome || 'Agente IA';
    respDist[nome] = (respDist[nome] || 0) + 1;
  });

  msg += `💬 Conversas WhatsApp:\n`;
  msg += `  📱 Total: ${convs.length}\n`;
  msg += `  🟢 Abertas: ${abertas}\n`;
  msg += `  ⏳ Aguardando: ${aguardando}\n`;
  msg += `  ✅ Encerradas: ${encerradas}\n`;

  if (Object.keys(respDist).length > 0) {
    msg += `  👥 Por responsável:\n`;
    for (const [nome, count] of Object.entries(respDist)) {
      msg += `    • ${nome}: ${count}\n`;
    }
  }
  msg += '\n';
}

// Estado do funil
if (boardData.stages && boardData.stages.length > 0) {
  msg += `📊 Funil (${boardData.total_leads || 0} leads):\n`;
  for (const stage of boardData.stages) {
    const count = stage.leads ? stage.leads.length : 0;
    const bar = '█'.repeat(Math.min(count, 20));
    msg += `  ${stage.nome}: ${count} ${bar}\n`;
  }
  msg += '\n';
}

// Acumulado do mês
msg += `🏆 Acumulado do mês:\n`;
msg += `  • Total de leads: ${kpisMes.total || 0}\n`;
msg += `  • Vendas: ${kpisMes.vendas || 0}\n`;
msg += `  • Em negociação: ${kpisMes.em_negociacao || 0}\n`;
msg += `  • Perdas: ${kpisMes.perdas || 0}\n\n`;

// Destinos mais procurados
const destinos = reportData.breakdown?.destinos || {};
const topDestinos = Object.entries(destinos).slice(0, 5);
if (topDestinos.length > 0) {
  msg += `🗺️ Top destinos do mês:\n`;
  for (const [destino, count] of topDestinos) {
    msg += `  • ${destino}: ${count} leads\n`;
  }
}

return [{
  json: {
    mensagem: msg,
    kpis_dia: kpis,
    kpis_mes: kpisMes,
    total_funil: boardData.total_leads || 0,
    data: dataHoje
  }
}];
